            if (maskB & (1 << i)) {
                countB++;
                xorB ^= nums[i];
            }
        }
        if (countB === 0) {
            andB = 0;
        } else {
            andB = -1;
            for (let i = 0; i < n; i++) {
                if (maskB & (1 << i)) {
                    andB &= nums[i];
                }
            }
        }
        const maskR = totalMask ^ maskB;
        const arrR: number[] = [];
        for (let i = 0; i < n; i++) {
            if (maskR & (1 << i)) {
                arrR.push(nums[i]);
            }
        }
        const TR = totalXOR ^ xorB;
        let xors = new Set<number>();
        xors.add(0);
        for (const num of arrR) {
            const newXors = new Set<number>(xors);
